const raw = $input.first().json;
const input = raw.body || raw;
let lead;
if (Array.isArray(input.contacts)) {
  lead = input.contacts[0] || null;
} else {
  lead = input;
}
if (!lead || (!lead.name && !lead.email && !lead.phone)) return [];
return [{ json: { lead } }];

const icpDescription = '{{ICP_DESCRIPTION}}';
const lead = $('Prepare Lead Data').first().json.lead;
const contactId = $('Save Contact').first().json.id || '';
if (!lead) return [];
return [{
  json: {
    contactId,
    claudeRequest: {
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 1024,
      system: 'You are a lead qualification specialist. ICP: ' + icpDescription + '. Score leads 0-100 based on ICP fit. Respond ONLY with valid JSON.',
      messages: [{
        role: 'user',
        content: 'Score this lead and return ONLY valid JSON with no extra text:\n{"score": <0-100>, "summary": "<2-sentence qualification summary>", "nextAction": "<recommended next step>", "tags": ["<tag1>", "<tag2>"]}\n\nLead data:\n' + JSON.stringify(lead, null, 2)
      }]
    }
  }
}];

const response = $input.first().json;
// Recover contactId from Build Claude Request node (survives through HTTP call via $json reference)
const contactId = $('Build Claude Request').first().json.contactId || '';
const text = (response.content && response.content[0] && response.content[0].text) ? response.content[0].text.trim() : '';
if (!text) return [{ json: { score: 0, summary: 'No response from Claude', nextAction: 'Manual review required', tags: ['needs-review'], contactId } }];
let result;
try {
  const clean = text.replace(/^```json\s*/i, '').replace(/```\s*$/i, '').trim();
  result = JSON.parse(clean);
} catch {
  result = { score: 0, summary: 'Could not parse AI response', nextAction: 'Manual review required', tags: ['needs-review'] };
}
const score = Math.min(100, Math.max(0, parseInt(result.score) || 0));
const tags = Array.isArray(result.tags) ? result.tags : [];
if (score >= 70 && !tags.includes('hot')) tags.push('hot');
else if (score >= 40 && !tags.includes('warm')) tags.push('warm');
else if (score < 40 && !tags.includes('cold')) tags.push('cold');
return [{ json: { score, summary: result.summary || '', nextAction: result.nextAction || '', tags, contactId } }];
